import { camelCaseToKebabCase } from './utils';
import { andesThemePrefix } from '../constants';

/** @param {string} name */
const toVarReference = (name) => `var(${name})`;

/** @param {string} value */
const toVarDefinition = (value, prefix = '') =>
  `--${prefix ? `${prefix}-` : ''}${value}`;

/** @param {string} value */
const isVarReference = (value) => (typeof value === 'string' && value.startsWith('{'));

/** @param {string} value */
const formatVarReferenceName = (value) => (typeof value === 'string'
  ? value.slice(1, -1).split('.').join('-')
  : '');

/** @param {string} value */
const extractPrefix = (value) => (typeof value === 'string'
  ? value.split('-')[0] || ''
  : '');

/**
 * @param {string} value
 * @param {Record<string, string>} varReferences
 */
const resolveVarReference = (value, varReferences) => {
  const valueAsToken = camelCaseToKebabCase(value);
  const referenceValue = varReferences[valueAsToken];

  if (referenceValue) {
    return toVarReference(toVarDefinition(valueAsToken));
  }

  return value;
};

/**
 * @param {Record<string, any>} obj
 * @param {string} prefix
 *
 * @returns {Record<string, unknown>}
 */
export const toVarNames = (obj, prefix = '') => Object.entries(obj).reduce((vars, [key, value]) => {
  const keyName = key === 'base' ? `${prefix}` : `${prefix}-${key}`;

  if (typeof value === 'object') {
    vars[key] = toVarNames(value, `${prefix ? `${prefix}-` : ''}${key}`);
  } else {
    vars[key] = toVarReference(toVarDefinition(camelCaseToKebabCase(keyName)));
  }
  return vars;
}, /** @type {Record<string, unknown>} */ ({}));

/**
 * @param {Record<string, any>} obj
 * @param {string} prefix
 *
 * @returns {Record<string, string>}
 */
export const toVarsMap = (obj = {}, prefix = '') =>
  Object.entries(obj).reduce((vars, [key, value]) => {
    if (typeof value === 'object') {
      const nestedVars = toVarsMap(
        value,
        `${prefix ? `${prefix}-` : ''}${key}`,
      );
      return { ...vars, ...nestedVars };
    }

    const varValue = isVarReference(value)
      ? `${extractPrefix(prefix)}-${formatVarReferenceName(value).replace('-base', '')}`
      : value;

    const keyName = key === 'base' ? `${prefix}` : `${prefix}-${key}`;

    return { ...vars, [camelCaseToKebabCase(keyName)]: varValue };
  }, {});

/**
 * @param {Record<string, string>} obj
 * @param {Record<string, string>} varReferences
 *
 * @returns {string}
 */
export const toCssVars = (obj = {}, varReferences = {}) =>
  Object.entries(obj)
    .map(([key, value]) => {
      const varName = toVarDefinition(key);
      const varValue = (typeof value === 'string' ? value.startsWith(extractPrefix(key)) : '')
        ? resolveVarReference(value, varReferences)
        : value;

      return `${varName}: ${varValue};`;
    })
    .join(' ');

/** @param {string} value */
export const isAndesCssVar = (value) => (typeof value === 'string' && value.startsWith(`--${andesThemePrefix}`));
