import React, { useContext, useMemo } from 'react';
import PropTypes from 'prop-types';
import { useId } from '@andes/context';
import { ThemeContext } from './ThemeContext';
import { useCreateTheme } from '../hooks/useCreateTheme';
import { useComponentRegister } from '../hooks/useComponentRegister';
// eslint-disable-next-line import/no-extraneous-dependencies
import { registerMetric } from '@andes/themes/build/metrics';
import { componentVariantPrefix } from '../constants';
import ThemeStyles from './ThemeStyles';

/** @type {typeof import('../..').AndesThemeProvider} */
const ThemeProvider = ({
  baseTheme = 'ML',
  children,
  id,
  override = false,
  stylesOptions,
  theme = {},
}) => {
  const { getThemedComponentClasses: parentGetThemedComponentClasses } = useContext(ThemeContext);

  const customId = useId(id).replace(/:/g, '');

  const {
    theme: providerTheme,
    getStyles: getCreateThemeStyles,
    componentsClasses,
    getComponentVariants,
    themeHash,
    themeVariables,
  } = useCreateTheme(theme, baseTheme, customId, override);

  const [themedComponents, registerComponent] = useComponentRegister();

  const { externalInject } = stylesOptions || {};

  /**
   * @param {string} component
   * @param {object} props
   */
  const getThemedComponentClasses = (component, props = {}) => {
    const parentThemeClass = typeof parentGetThemedComponentClasses === 'function'
      ? parentGetThemedComponentClasses(component, props)
      : '';
    const componentClass = componentsClasses.get(component)?.className || '';

    let componentClassNames = componentClass;
    if (parentThemeClass) {
      componentClassNames = componentClass
        ? `${parentThemeClass} ${componentClass}`
        : parentThemeClass;
    }

    if (!componentClassNames) {
      return '';
    }

    const componentVariants = getComponentVariants(component, props);
    registerComponent(component, componentClassNames, componentVariants);

    const themedComponent = themedComponents.get(component);
    if (!themedComponent) {
      return '';
    }

    const componentBaseClassName = themedComponent?.className;
    const componentVariantsClassName = componentVariants
      .reduce((classNames, variant) => {
        classNames.push(`${componentVariantPrefix}${variant.id}`);
        return classNames;
      }, /** @type {string[] } */ ([]))
      .join(' ');

    const className = `${componentBaseClassName} ${componentVariantsClassName}`.trim();
    return className;
  };

  const getThemeStyles = () => {
    const { buildOn = 'SSR', global } = stylesOptions || {};
    const compliesRenderStylesCondition = buildOn === 'SSR'
      ? true // Always render styles on server side to avoid missmatch with client side
      : typeof window !== 'undefined';

    return compliesRenderStylesCondition
      ? getCreateThemeStyles(themedComponents, global)
      : '';
  };

  const contextValue = useMemo(
    () => ({
      theme: providerTheme,
      getThemedComponentClasses,
      getThemeStyles,
      themeHash,
      themeVariables,
    }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [theme],
  );

  registerMetric(theme);

  return (
    <ThemeContext.Provider value={contextValue}>
      <div id={customId} style={{ display: 'contents' }}>
        {children}
        {!externalInject ? <ThemeStyles /> : null}
      </div>
    </ThemeContext.Provider>
  );
};

ThemeProvider.displayName = 'AndesThemeProvider';

ThemeProvider.propTypes = {
  children: PropTypes.node.isRequired,
  baseTheme: PropTypes.oneOf(['ML', 'MP']),
  id: PropTypes.string,
  stylesOptions: PropTypes.shape({}),
  theme: PropTypes.shape({}),
  override: PropTypes.bool,
};

export default ThemeProvider;
