import { andesThemePrefix } from '../../constants';
import { createCssVarsThemeStyles } from './ThemeStylesBuilder';

/** @typedef {import('../../..').AndesProviderTheme} Theme */

/**
 * @param {Theme["components"]} components
 * @param {string} id
 * @param {string} prefix
 *
 * @returns {import('../../..').GetComponentsStyles}
 */
const registerComponentsClasses = (components, id, prefix) => {
  if (typeof components !== 'object') {
    return new Map();
  }

  return new Map(
    Object.entries(components).map(([component, componentStyles]) => [
      component,
      {
        className: `${prefix}-${id}-${component}`,
        variants: componentStyles?.variants || [],
      },
    ]),
  );
};

/**
  * @param {import('../../..').CustomVariant} variant
  * @param {object} componentProps
  */
const variantMatch = (variant, componentProps) =>
  (typeof variant.propsMatcher === 'function'
    ? variant.propsMatcher(componentProps)
    : Object.keys(variant.propsMatcher).every(
      (key) =>
        // eslint-disable-next-line max-len
        componentProps[/** @type {keyof typeof componentProps} */ (key)] === /** @type { Record<string, unknown> } */(variant.propsMatcher)[key],
    ));

/**
 * @param {Theme} theme
 * @param {string} id
 */
export const createTheme = (theme, id) => {
  const { components = {} } = theme;

  const hashKey = 'data-t-hash';
  const themeHash = { [hashKey]: id };
  const componentsClasses = registerComponentsClasses(
    components,
    id,
    andesThemePrefix,
  );
  const { getCoreStyles, getComponentsStyles, themeVariables } = createCssVarsThemeStyles(
    theme,
    andesThemePrefix,
    themeHash,
  );

  /**
   * @param {string} component
   * @param {object} componentProps
   */
  const getComponentVariants = (component, componentProps) => {
    let variants = /** @type import('../../..').CustomVariant[] */ ([]);

    if (Object.keys(componentProps).length > 0) {
      const componentVariants = components[component]?.variants || [];
      variants = componentVariants.filter((variant) => variantMatch(variant, componentProps));
    }

    return variants;
  };

  /**
   * @param {import('../../..').GetComponentsStyles} styledComponents
   * @param {boolean} [global]
   */
  const getStyles = (styledComponents = componentsClasses, global = false) => {
    const style = (
      getCoreStyles() + getComponentsStyles(styledComponents)
    ).replace(/ {2,}|\n/g, '');
    return style.length > 0
      ? `${global ? 'body' : `div#${id}, [data-andes-portal][${hashKey}=${id}], [data-andes-popper-outside-root][${hashKey}=${id}]`}{${style}}`
      : '';
  };

  return { getStyles, componentsClasses, themeHash, getComponentVariants, themeVariables };
};
